create extension if not exists "pgcrypto";
create table if not exists profiles (id uuid primary key default gen_random_uuid(), name text not null, phone text unique, admission_roll text, batch_no text, role text not null default 'student' check (role in ('admin','student')), status text default 'active', created_at timestamptz default now());
create table if not exists courses (id uuid primary key default gen_random_uuid(), name text not null, slug text unique, status text default 'active', created_at timestamptz default now());
create table if not exists batches (id uuid primary key default gen_random_uuid(), course_id uuid references courses(id) on delete cascade, name text not null, status text default 'active', created_at timestamptz default now());
create table if not exists quizzes (id uuid primary key default gen_random_uuid(), course_id uuid references courses(id) on delete set null, batch_id uuid references batches(id) on delete set null, title text not null, subject text, chapter text, time_limit_minutes int default 40, marks_per_question numeric default 1, negative_mark numeric default 0, status text default 'draft' check (status in ('draft','published','closed')), start_at timestamptz, end_at timestamptz, show_result boolean default true, show_correct_answer boolean default true, show_explanation boolean default true, created_at timestamptz default now(), updated_at timestamptz default now());
create table if not exists questions (id uuid primary key default gen_random_uuid(), quiz_id uuid references quizzes(id) on delete cascade, subject text, chapter text, question_text text not null, option_a text not null, option_b text not null, option_c text not null, option_d text not null, correct_option text not null check (correct_option in ('A','B','C','D')), explanation text, difficulty text default 'Easy', position int default 0, created_at timestamptz default now());
create table if not exists attempts (id uuid primary key default gen_random_uuid(), quiz_id uuid references quizzes(id) on delete cascade, student_id uuid references profiles(id) on delete cascade, started_at timestamptz default now(), submitted_at timestamptz, score numeric default 0, total_marks numeric default 0, correct_count int default 0, wrong_count int default 0, unanswered_count int default 0, time_taken_seconds int default 0, status text default 'submitted', created_at timestamptz default now(), unique(quiz_id,student_id));
create table if not exists student_answers (id uuid primary key default gen_random_uuid(), attempt_id uuid references attempts(id) on delete cascade, question_id uuid references questions(id) on delete cascade, selected_option text, is_correct boolean default false, marks_obtained numeric default 0, created_at timestamptz default now());
create table if not exists csv_uploads (id uuid primary key default gen_random_uuid(), quiz_id uuid references quizzes(id) on delete cascade, file_name text, total_rows int default 0, inserted_rows int default 0, skipped_rows int default 0, error_log jsonb, created_at timestamptz default now());
create index if not exists idx_quizzes_status_schedule on quizzes(status,start_at,end_at); create index if not exists idx_questions_quiz on questions(quiz_id); create index if not exists idx_attempts_quiz_student on attempts(quiz_id,student_id);
insert into courses(name,slug,status) values('Diploma Admission Care 2026-27','diploma-admission-care-2026-27','active') on conflict(slug) do nothing;
insert into batches(course_id,name,status) select id,'Batch-01','active' from courses where slug='diploma-admission-care-2026-27' and not exists(select 1 from batches where name='Batch-01');
